#if PROPERTY(Persistent) == "true"
if 'NODEID{}' in self.savedVars:
	VAR.W{Value} = self.savedVars['NODEID{}']
	PROPAGATE{Value}
#endif

#if PROPERTY(Persistent) == "true"
if 'NODEID{}' in self.savedVars:
	VAR.W{Value} = self.savedVars['NODEID{}']
	PROPAGATE{Value}
#endif

#if PROPERTY(Persistent) == "true"
if 'NODEID{}' in self.savedVars:
	VAR.W{Value} = self.savedVars['NODEID{}']
	PROPAGATE{Value}
#endif

#if PROPERTY(Persistent) == "true"
if 'NODEID{}' in self.savedVars:
	VAR.W{Value} = self.savedVars['NODEID{}']
	PROPAGATE{Value}
#endif

#if PROPERTY(Persistent) == "true"
if 'NODEID{}' in self.savedVars:
	VAR.W{Value} = self.savedVars['NODEID{}']
	PROPAGATE{Value}
#endif

Node.InitScript:
#if CONNECTED(Started)
def acceptedCb(args):
	VAR.W{Player} = self.owner
	PROPAGATE{Player}
	TRIGGER{Started}
	return PROPERTY{Stop Propagating Event}
	
LOCAL{AcceptedId} = self.owner.subscribe("mission.accepted::" + str(PROPERTY{Mission Id}), acceptedCb, once = PROPERTY{Fire Only Once})
#endif

#if CONNECTED(Completed)
def completedCb(args):
	VAR.W{Player} = self.owner
	PROPAGATE{Player}
	TRIGGER{Completed}
	return PROPERTY{Stop Propagating Event}
	
LOCAL{CompletedId} = self.owner.subscribe("mission.completed::" + str(PROPERTY{Mission Id}), completedCb, once = PROPERTY{Fire Only Once})
#endif

#if CONNECTED(Failed)
def failedCb(args):
	VAR.W{Player} = self.owner
	PROPAGATE{Player}
	TRIGGER{Failed}
	return PROPERTY{Stop Propagating Event}
	
LOCAL{FailedId} = self.owner.subscribe("mission.failed::" + str(PROPERTY{Mission Id}), failedCb, once = PROPERTY{Fire Only Once})
#endif

#if CONNECTED(Rewards Chosen)
def rewardsCb(args):
	VAR.W{Player} = self.owner
	PROPAGATE{Player}
	TRIGGER{Rewards Chosen}
	return PROPERTY{Stop Propagating Event}
	
LOCAL{RewardsId} = self.owner.subscribe("mission.rewards_chosen::" + str(PROPERTY{Mission Id}), rewardsCb, once = PROPERTY{Fire Only Once})
#endif

def cb(args):
	TRIGGER.P{Triggered}
	
LOCAL{EventId} = self.owner.subscribe(PROPERTY{Event Name}, cb, once = PROPERTY{Fire Only Once})

def cb(args):
	VAR{Event Invoker} = args['invoker']
	PROPAGATE{Event Invoker}
	TRIGGER.P{Triggered}
	
LOCAL{EventId} = self.owner.subscribe('designer::' + PROPERTY{Event Name}, cb)

	#if CONNECTED(Make Gate)
	def makeGateCb(args):
		VAR.W{Stargate Id} = args['stargateId']
		PROPAGATE{Stargate Id}
		VAR.W{Entity} = self.owner
		PROPAGATE{Entity}
		TRIGGER{Make Gate}

	LOCAL{MakeGateSubscriptionId} = self.owner.subscribe("stargate::make", makeGateCb, once = PROPERTY{Fire Only Once})
	#endif
	
	#if CONNECTED(Make Gate Failed)
	def makeGateFailedCb(args):
		VAR.W{Stargate Id} = args['stargateId']
		PROPAGATE{Stargate Id}
		VAR.W{Entity} = self.owner
		PROPAGATE{Entity}
		TRIGGER{Make Gate Failed}

	LOCAL{MakeGateFailedSubscriptionId} = self.owner.subscribe("stargate::makefailed", makeGateFailedCb, once = PROPERTY{Fire Only Once})
	#endif
	
	#if CONNECTED(Destroy Gate)
	def destroyGateCb(args):
		VAR.W{Stargate Id} = args['stargateId']
		PROPAGATE{Stargate Id}
		VAR.W{Entity} = self.owner
		PROPAGATE{Entity}
		TRIGGER{Destroy Gate}

	LOCAL{DestroyGateSubscriptionId} = self.owner.subscribe("stargate::destroy", destroyGateCb, once = PROPERTY{Fire Only Once})
	#endif
	
	#if CONNECTED(Gate Passage)
	def gatePassageCb(args):
		VAR.W{Stargate Id} = args['stargateId']
		PROPAGATE{Stargate Id}
		VAR.W{Entity} = self.owner
		PROPAGATE{Entity}
		TRIGGER{Gate Passage}

	LOCAL{GatePassageSubscriptionId} = self.owner.subscribe("stargate::passage", gatePassageCb, once = PROPERTY{Fire Only Once})
	#endif

	def dialogCb(args):
		VAR.W{Dialog Set Map Id} = args['dialogSetMapId']
		PROPAGATE{Dialog Set Map Id}
		VAR.W{Player} = args['player']
		PROPAGATE{Player}
		TRIGGER{Out}
		return PROPERTY{Stop Propagating Event}

	LOCAL{SubscriptionId} = self.owner.subscribe("dialog.open::" + str(PROPERTY{Dialog Id}), dialogCb, once = PROPERTY{Fire Only Once})

	def dialogSetCb(args):
		VAR.W{Player} = args['player']
		PROPAGATE{Player}
		VAR.W{Target} = args['target']
		PROPAGATE{Target}
		TRIGGER{Out}
		return PROPERTY{Stop Propagating Event}

	LOCAL{SubscriptionId} = self.owner.subscribe("dialog_set.open::" + str(PROPERTY{Dialog Set Map Id}), dialogSetCb, once = PROPERTY{Fire Only Once})

	def dialogChoiceCb(args):
		VAR.W{Button Id} = args['buttonId']
		PROPAGATE{Button Id}
		VAR.W{Player} = args['player']
		PROPAGATE{Player}
		TRIGGER{Out}
		return PROPERTY{Stop Propagating Event}

	LOCAL{SubscriptionId} = self.owner.subscribe("dialog.choice::" + str(PROPERTY{Dialog Id}), dialogChoiceCb, once = PROPERTY{Fire Only Once})

	def interactCb(args):
		VAR.W{Target} = args['target']
		PROPAGATE{Target}
		# TODO: Move this to a "Player Variable" node (Entity type)
		VAR.W{Player} = self.owner
		PROPAGATE{Player}
		TRIGGER{Out}
		return PROPERTY{Stop Propagating Event}

	#ifn PROPERTY(Template Name) == ""
	LOCAL{TplSubscriptionId} = self.owner.subscribe("entity.interact.template::" + PROPERTY{Template Name}, interactCb, once = PROPERTY{Fire Only Once})
	#endif
	#ifn PROPERTY(Tag) == ""
	LOCAL{TagSubscriptionId} = self.owner.subscribe("entity.interact.tag::" + PROPERTY{Tag}, interactCb, once = PROPERTY{Fire Only Once})
	#endif

	def spawnedCb(args):
		VAR.W{Entity} = args['entity']
		PROPAGATE{Entity}
		TRIGGER{Out}
		return PROPERTY{Stop Propagating Event}

	#ifn PROPERTY(Template Name) == ""
	LOCAL{TplSubscriptionId} = self.owner.space.subscribe("entity.spawned.template::" + PROPERTY{Template Name}, spawnedCb, once = PROPERTY{Fire Only Once})
	#endif
	#ifn PROPERTY(Tag) == ""
	LOCAL{TagSubscriptionId} = self.owner.space.subscribe("entity.spawned.tag::" + PROPERTY{Tag}, spawnedCb, once = PROPERTY{Fire Only Once})
	#endif

	def deadCb(args):
		VAR.W{Entity} = args['entity']
		PROPAGATE{Entity}
		TRIGGER{Out}
		return PROPERTY{Stop Propagating Event}

	#ifn PROPERTY(Template Name) == ""
	LOCAL{TplSubscriptionId} = self.owner.space.subscribe("entity.dead.template::" + PROPERTY{Template Name}, deadCb, once = PROPERTY{Fire Only Once})
	#endif
	#ifn PROPERTY(Tag) == ""
	LOCAL{TagSubscriptionId} = self.owner.space.subscribe("entity.dead.tag::" + PROPERTY{Tag}, deadCb, once = PROPERTY{Fire Only Once})
	#endif

	def regionCb(args):
		VAR.W{Region Id} = args['regionId']
		PROPAGATE{Region Id}
		VAR.W{Invoker} = args['entity']
		PROPAGATE{Invoker}
		if args['entering']:
			TRIGGER.P{Entered}
		else:
			TRIGGER.P{Left}

	LOCAL{SubscriptionId} = self.owner.subscribe("client_hinted_region::" + PROPERTY{Tag}, regionCb, once = PROPERTY{Fire Only Once})

	def loaded(args):
		VAR.W{Player} = self.owner
		PROPAGATE{Player}
		TRIGGER{Out}

	LOCAL{SubscriptionId} = self.owner.subscribe("player.loaded", loaded)

	def teleportCb(args):
		#ifn PROPERTY(Region Id) == "0"
		if args['regionId'] != PROPERTY{Region Id}:
			return False
		#endif
		
		VAR.W{Region Id} = args['regionId']
		PROPAGATE{Region Id}
		VAR.W{Player} = self.owner
		PROPAGATE{Player}
		TRIGGER{Out}
		
		return PROPERTY{Stop Propagating Event}

	LOCAL{HandlerId} = self.owner.subscribe('teleport::in', teleportCb, once = PROPERTY{Fire Only Once})

	def teleportCb(args):
		#ifn PROPERTY(Src Region Id) == "0"
		if args['regionId'] != PROPERTY{Src Region Id}:
			return False
		#endif
		
		#ifn PROPERTY(Dst Region Id) == "0"
		if args['destinationRegionId'] != PROPERTY{Dst Region Id}:
			return False
		#endif
		
		VAR.W{Src Region Id} = args['regionId']
		PROPAGATE{Src Region Id}
		VAR.W{Dst Region Id} = args['destinationRegionId']
		PROPAGATE{Dst Region Id}
		VAR.W{Player} = self.owner
		PROPAGATE{Player}
		TRIGGER{Out}
		
		return PROPERTY{Stop Propagating Event}

	LOCAL{HandlerId} = self.owner.subscribe('teleport::out', teleportCb, once = PROPERTY{Fire Only Once})

Node.Port:
#if CONNECTED(A == B)
if VAR.R{A} == VAR.R{B}:
	TRIGGER.P{A == B}
#endif
#if CONNECTED(A != B)
if VAR.R{A} != VAR.R{B}:
	TRIGGER.P{A != B}
#endif

#if CONNECTED(A == B)
if VAR.R{A} == VAR.R{B}:
	TRIGGER.P{A == B}
#endif
#if CONNECTED(A != B)
if VAR.R{A} != VAR.R{B}:
	TRIGGER.P{A != B}
#endif
#if CONNECTED(A < B)
if VAR.R{A} < VAR.R{B}:
	TRIGGER.P{A < B}
#endif
#if CONNECTED(A > B)
if VAR.R{A} > VAR.R{B}:
	TRIGGER.P{A > B}
#endif

#if CONNECTED(A == B)
if VAR.R{A} == VAR.R{B}:
	TRIGGER.P{A == B}
#endif
#if CONNECTED(A != B)
if VAR.R{A} != VAR.R{B}:
	TRIGGER.P{A != B}
#endif
#if CONNECTED(A < B)
if VAR.R{A} < VAR.R{B}:
	TRIGGER.P{A < B}
#endif
#if CONNECTED(A > B)
if VAR.R{A} > VAR.R{B}:
	TRIGGER.P{A > B}
#endif

#if CONNECTED(A == B)
if VAR.R{A} == VAR.R{B}:
	TRIGGER.P{A == B}
#endif
#if CONNECTED(A != B)
if VAR.R{A} != VAR.R{B}:
	TRIGGER.P{A != B}
#endif

#if CONNECTED(A == B)
if VAR.R{A} == VAR.R{B}:
	TRIGGER.P{A == B}
#endif
#if CONNECTED(A != B)
if VAR.R{A} != VAR.R{B}:
	TRIGGER.P{A != B}
#endif

#if CONNECTED(A == B)
if VAR.R{A} == VAR.R{B}:
	TRIGGER.P{A == B}
#endif
#if CONNECTED(A != B)
if VAR.R{A} != VAR.R{B}:
	TRIGGER.P{A != B}
#endif

LOCAL{Value} = VAR.R{Set Value}
a = VAR_OR_PROP{A}
#if CONNECTED(Value == A)
if LOCAL{Value} == a:
	TRIGGER.P{Value == A}
#endif
#if CONNECTED(Value != A)
if LOCAL{Value} != a:
	TRIGGER.P{Value != A}
#endif
#if CONNECTED(Value < A)
if LOCAL{Value} < a:
	TRIGGER.P{Value < A}
#endif
#if CONNECTED(Value > A)
if LOCAL{Value} > a:
	TRIGGER.P{Value > A}
#endif

LOCAL{Value} += PROPERTY{Increment}
a = VAR_OR_PROP{A}
#if CONNECTED(Value == A)
if LOCAL{Value} == a:
	TRIGGER.P{Value == A}
#endif
#if CONNECTED(Value != A)
if LOCAL{Value} != a:
	TRIGGER.P{Value != A}
#endif
#if CONNECTED(Value < A)
if LOCAL{Value} < a:
	TRIGGER.P{Value < A}
#endif
#if CONNECTED(Value > A)
if LOCAL{Value} > a:
	TRIGGER.P{Value > A}
#endif

changed = self.effect.changeStat(VAR_OR_PROP{Stat Id}, VAR_OR_PROP{Change Type}, VAR_OR_PROP{Amount}, VAR_OR_PROP{Is Permanent})
VAR.W{Difference} = changed
PROPAGATE{Difference}
TRIGGER{Out}

VAR.W{Value} = random.uniform(VAR_OR_PROP{Min Value}, VAR_OR_PROP{Max Value})
PROPAGATE{Value}
TRIGGER{Out}

if random.uniform(0, 1) > VAR_OR_PROP{Probability %}:
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity}.abilities.hasMoniker(zlib.crc32(VAR_OR_PROP{Moniker})):
	TRIGGER.P{Found}
#if CONNECTED(Not Found)
else:
	TRIGGER.P{Not Found}
#endif

if VAR.R{Entity}.abilities.hasEffect(VAR_OR_PROP{Effect Id}):
	TRIGGER.P{Found}
#if CONNECTED(Not Found)
else:
	TRIGGER.P{Not Found}
#endif

invoker = VAR.R{Invoker}
effect = DefMgr.get('effect', VAR_OR_PROP{Effect Id})
VAR.R{Entity}.abilities.addEffect(effect, invoker.entityId if invoker else 0)
TRIGGER.P{Out}

tpl = DefMgr.get('template', VAR_OR_PROP{Template Id})
if tpl and VAR.R{Location}:
	entity = self.owner.space.createEntity(tpl, VAR.R{Location})
	VAR.W{Entity} = entity
	PROPAGATE{Entity}
	TRIGGER{Spawned}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity}:
	VAR.R{Entity}.getStat(Atrea.enums.health).setCurrent(0)
	TRIGGER{Killed}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity} is not None:
	if Atrea.destroyCellEntity(VAR.R{Entity}.entityId):
		TRIGGER.P{Despawned}
#if CONNECTED(Failed)
	else:
		TRIGGER.P{Failed}
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity} is not None:
	#if CONNECTED(Completed)
	def waypointCb():
		TRIGGER.P{Completed}
	VAR.R{Entity}.addWaypoint(VAR.R{Position}, waypointCb)
	#endif
	#ifn CONNECTED(Completed)
	VAR.R{Entity}.addWaypoint(VAR.R{Position}, lambda: None)
	#endif
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

VAR.W{Entity} = None
if VAR.R{Entity Id} is not None:
	VAR.W{Entity} = Atrea.findEntityOnSpace(VAR.R{Entity Id}, self.owner.space.spaceId)
else:
	tpl = VAR_OR_PROP{Template Tag}
	tag = VAR_OR_PROP{Tag}
	entities = Atrea.findEntities(self.owner.space.spaceId)
	
	if tag:
		for entity in entities:
			if entity.tag == tag:
				VAR.W{Entity} = entity
				break
	elif tpl:
		for entity in entities:
			if entity.template is not None and entity.template.name == tpl:
				VAR.W{Entity} = entity
				break
	else:
		VAR.W{Entity} = None
PROPAGATE{Entity}
if VAR.R{Entity} is not None:
	TRIGGER.P{Found}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

ent = VAR.R{Entity}
if ent is None:
	TRIGGER{Failed}
	return
	
#if CONNECTED(Static Mesh)
if VAR.R{Static Mesh} is not None:
	ent.setStaticMeshName(VAR.R{Static Mesh})
#endif
	
#if CONNECTED(Body Set)
if VAR.R{Body Set} is not None:
	ent.setBodySet(VAR.R{Body Set})
#endif
	
#if CONNECTED(Name)
if VAR.R{Name} is not None:
	ent.setName(VAR.R{Name})
#endif
	
#if CONNECTED(Alignment)
if VAR.R{Alignment} is not None:
	ent.setAlignment(VAR.R{Alignment})
#endif
	
#if CONNECTED(Faction)
if VAR.R{Faction} is not None:
	ent.setFaction(VAR.R{Faction})
#endif
	
#if CONNECTED(Static Mesh)
if VAR.R{Archetype} is not None:
	ent.setArchetype(VAR.R{Archetype})
#endif
	
#if CONNECTED(Aggression)
if VAR.R{Aggression} is not None:
	ent.setAggression(VAR.R{Aggression})
#endif
	
#if CONNECTED(Level)
if VAR.R{Level} is not None:
	ent.setLevel(VAR.R{Level})
#endif
	
#if CONNECTED(Name Id)
if VAR.R{Name Id} is not None:
	ent.setNameId(VAR.R{Name Id})
#endif
	
#if CONNECTED(Event Set)
if VAR.R{Event Set} is not None:
	ent.setEventSet(VAR.R{Event Set})
#endif
	
#if CONNECTED(Interaction Type)
if VAR.R{Interaction Type} is not None:
	ent.setInteractionType(VAR.R{Interaction Type})
#endif
	
#if CONNECTED(Visible)
if VAR.R{Visible} is not None:
	ent.setVisible(VAR.R{Visible})
#endif

TRIGGER{Successful}

entity = VAR.R{Entity}
if entity is None:
	TRIGGER{Failed}
	return

entity.setInteractionType(entity.interactionType | VAR_OR_PROP{Interaction Type})
TRIGGER{Successful}

entity = VAR.R{Entity}
if entity is None:
	TRIGGER{Failed}
	return
	
entity.setInteractionType(entity.interactionType & ~VAR_OR_PROP{Interaction Type})
TRIGGER{Successful}

entity = VAR.R{Entity}
if entity is not None:
	#if CONNECTED(Position)
	VAR.W{Position} = entity.position
	PROPAGATE{Position}
	#endif
	
	#if CONNECTED(Rotation)
	VAR.W{Rotation} = entity.rotation
	PROPAGATE{Rotation}
	#endif
	
TRIGGER.P{Out}

entity = VAR.R{Entity}
#if CONNECTED(Failed)
if entity is None:
	TRIGGER.P{Failed}
#endif

if entity is not None:
	#if CONNECTED(Static Mesh)
	VAR.W{Static Mesh} = entity.staticMesh
	PROPAGATE{Static Mesh}
	#endif
	
	#if CONNECTED(Body Set)
	VAR.W{Body Set} = entity.bodySet
	PROPAGATE{Body Set}
	#endif
	
	#if CONNECTED(Name)
	VAR.W{Name} = entity.beingName
	PROPAGATE{Name}
	#endif
	
	#if CONNECTED(Tag)
	if entity.tag is not None:
		VAR.W{Tag} = entity.tag
		PROPAGATE{Tag}
	#endif
	
	#if CONNECTED(Alignment)
	VAR.W{Alignment} = entity.alignment
	PROPAGATE{Alignment}
	#endif
	
	#if CONNECTED(Faction)
	VAR.W{Faction} = entity.faction
	PROPAGATE{Faction}
	#endif
	
	#if CONNECTED(Archetype)
	VAR.W{Archetype} = entity.archetype
	PROPAGATE{Archetype}
	#endif
	
	#if CONNECTED(Aggression)
	VAR.W{Aggression} = entity.aggression
	PROPAGATE{Aggression}
	#endif
	
	#if CONNECTED(Level)
	VAR.W{Level} = entity.level
	PROPAGATE{Level}
	#endif
	
	#if CONNECTED(Name Id)
	VAR.W{Name Id} = entity.nameId
	PROPAGATE{Name Id}
	#endif
	
	#if CONNECTED(Event Set)
	VAR.W{Event Set} = entity.kismetEventSetId
	PROPAGATE{Event Set}
	#endif
	
	#if CONNECTED(Item Event Set)
	VAR.W{Item Event Set} = Constants.ARCHETYPE_ITEM_EVENT_SETS[entity.archetype]
	PROPAGATE{Item Event Set}
	#endif
	
	#if CONNECTED(Interaction Flags)
	VAR.W{Interaction Flags} = entity.interactionFlags
	PROPAGATE{Interaction Flags}
	#endif
	
	#if CONNECTED(Visible)
	VAR.W{Visible} = entity.visible
	PROPAGATE{Visible}
	#endif
	
	TRIGGER.P{Successful}

if VAR.R{Entity}:
	stat = VAR.R{Entity}.getStat(VAR_OR_PROP{Stat Id})
	#if CONNECTED(Min)
	VAR.W{Min} = stat.min
	PROPAGATE{Min}
	#endif
	#if CONNECTED(Current)
	VAR.W{Current} = stat.cur
	PROPAGATE{Current}
	#endif
	#if CONNECTED(Max)
	VAR.W{Max} = stat.max
	PROPAGATE{Max}
	#endif
	
	#if CONNECTED(Base Min)
	VAR.W{Base Min} = stat.baseMin
	PROPAGATE{Base Min}
	#endif
	#if CONNECTED(Base Current)
	VAR.W{Base Current} = stat.baseCur
	PROPAGATE{Base Current}
	#endif
	#if CONNECTED(Base Max)
	VAR.W{Base Max} = stat.baseMax
	PROPAGATE{Base Max}
	#endif
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

pos = VAR.R{Entity}.position
tpos = VAR.R{Target}.position
dv = Atrea.Vector3(pos.x - tpos.x, pos.y - tpos.y, pos.z - tpos.z)
VAR.W{Distance} = dv.length()
PROPAGATE{Distance}
TRIGGER{Out}

if VAR.R{Entity} is not None and VAR.R{Target} is not None:
	VAR.W{Facing} = VAR.R{Entity}.facing(VAR.R{Target})
	PROPAGATE{Facing}
	VAR.W{Facing Type} = VAR.R{Entity}.facingType(VAR.R{Target})
	PROPAGATE{Facing Type}
TRIGGER{Out}

if VAR.R{Entity} and VAR_OR_PROP{Component}:
	VAR.R{Entity}.addBodyComponent(VAR_OR_PROP{Component})
	TRIGGER{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity} and VAR_OR_PROP{Component}:
	VAR.R{Entity}.removeBodyComponent(VAR_OR_PROP{Component})
	TRIGGER{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

target = VAR.R{Target}
instigator = VAR.R{Instigator}
if target is not None and instigator is not None and hasattr(target, 'threatGenerated'):
	target.threatGenerated(instigator.entityId, VAR_OR_PROP{Threat Level})
	TRIGGER{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

entity = VAR.R{Entity}
if entity is not None and hasattr(entity, 'generateLoot'):
	entity.generateLoot()
	TRIGGER{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity}.getCombatantStateFlag(VAR_OR_PROP{State Flag}):
	TRIGGER.P{Set}
#if CONNECTED(Not Set)
else:
	TRIGGER.P{Not Set}
#endif

pos = VAR.R{Destination}
VAR.R{Target}.moveTo(pos.x, pos.y, pos.z, worldName = VAR_OR_PROP{World Name} or None)
TRIGGER{Out}

id = VAR_OR_PROP{Ability Id}
ability = DefMgr.get('ability', id)
if ability and VAR.R{Actor} and VAR.R{Actor}.abilities.launchAbility(ability, targetId = VAR.R{Target}.entityId if VAR.R{Target} else None,
	targetLoc = VAR.R{Target Location}, autoCycle = False, isEntityAbility = PROPERTY{Is Entity Ability}):
	#if CONNECTED(Interrupted)
	def interrupted(args):
		TRIGGER.P{Interrupted}
	LOCAL{InterruptedId} = self.owner.subscribe("ability.interrupted::" + str(id), interrupted, once = True)
	#endif
	#if CONNECTED(Finished)
	def finished(args):
		TRIGGER.P{Finished}
	LOCAL{FinishedId} = self.owner.subscribe("ability.finished::" + str(id), finished, once = True)
	#endif
	TRIGGER.P{Launched}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

status = VAR.R{Player}.missions.getMissionStatus(VAR_OR_PROP{Mission Id})
#if CONNECTED(Not Accepted)
if status == Constants.MISSION_Not_Active:
	TRIGGER.P{Not Accepted}
#endif
#if CONNECTED(Active)
if status == Constants.MISSION_Active:
	TRIGGER.P{Active}
#endif
#if CONNECTED(Failed)
if status == Constants.MISSION_Failed:
	TRIGGER.P{Failed}
#endif
#if CONNECTED(Completed)
if status == Constants.MISSION_Completed:
	TRIGGER.P{Completed}
#endif

status = VAR.R{Player}.missions.getStepStatus(VAR_OR_PROP{Mission Id}, VAR_OR_PROP{Step Id})
#if CONNECTED(Not Started)
if status == Constants.MISSION_Not_Active:
	TRIGGER.P{Not Started}
#endif
#if CONNECTED(Active)
if status == Constants.MISSION_Active:
	TRIGGER.P{Active}
#endif
#if CONNECTED(Completed)
if status == Constants.MISSION_Completed:
	TRIGGER.P{Completed}
#endif

status = VAR.R{Player}.missions.getObjectiveStatus(VAR_OR_PROP{Mission Id}, VAR_OR_PROP{Objective Id})
#if CONNECTED(Not Started)
if status == Constants.MISSION_Not_Active:
	TRIGGER.P{Not Started}
#endif
#if CONNECTED(Pending)
if status == Constants.MISSION_Active:
	TRIGGER.P{Pending}
#endif
#if CONNECTED(Completed)
if status == Constants.MISSION_Completed:
	TRIGGER.P{Completed}
#endif
#if CONNECTED(Failed)
if status == Constants.MISSION_Failed:
	TRIGGER.P{Failed}
#endif

if VAR.R{Player} is None or not VAR_OR_PROP{Design}:
	TRIGGER{Failed}
	return
	
if not VAR_OR_PROP{Bag}:
	added = VAR.R{Player}.inventory.pickedUpItem(VAR_OR_PROP{Design}, VAR_OR_PROP{Quantity} or 1)
else:
	added = VAR.R{Player}.inventory.addItem(VAR_OR_PROP{Bag}, VAR_OR_PROP{Design}, VAR_OR_PROP{Quantity} or 1)
VAR.R{Player}.inventory.flushUpdates()
	
if added:
	TRIGGER.P{Added}
else:
	TRIGGER.P{Failed}

if VAR.R{Player} and (VAR_OR_PROP{Design} or VAR.R{Item Id}):
	removed = False
	#if CONNECTED(Item Id)
	if VAR.R{Item Id}:
		removed = VAR.R{Player}.inventory.removeItem(VAR.R{Item Id}, VAR_OR_PROP{Quantity}, PROPERTY{Forced})
	#endif
	
	if not removed and VAR_OR_PROP{Design}:
		removed = VAR.R{Player}.inventory.removeItemByDesign(VAR_OR_PROP{Design}, VAR_OR_PROP{Quantity}, PROPERTY{Forced})
	VAR.R{Player}.inventory.flushUpdates()
	
	if removed:
		TRIGGER.P{Removed}
	#if CONNECTED(Failed)
	else:
		TRIGGER.P{Failed}
	#endif
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

item = VAR.R{Player}.inventory.findItem(VAR_OR_PROP{Design}, VAR_OR_PROP{Search Bag} or None, not PROPERTY{Search Equipment Bags})
if item is not None:
	VAR.W{Bag} = item.bagId
	PROPAGATE{Bag}
	VAR.W{Slot} = item.slotId
	PROPAGATE{Slot}
	TRIGGER.P{Found}
else:
	TRIGGER.P{Not Found}

bag = VAR.R{Player}.inventory.getBag(VAR_OR_PROP{Bag}) if VAR.R{Player} else None
slot = bag.activeSlotId if bag else None
if slot is not None:
	VAR.W{Slot Id} = slot
	PROPAGATE{Slot Id}
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Entity} is not None:
	VAR.W{Ammo Stat Id} = VAR.R{Entity}.getAmmoStat()
	PROPAGATE{Ammo Stat Id}
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Player} and VAR.R{Player}.inventory.updateActiveSlot(VAR_OR_PROP{Bag}, VAR_OR_PROP{Slot Id}):
	VAR.R{Player}.inventory.flushUpdates()
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

if VAR.R{Player}:
	VAR.R{Player}.addStargateAddress(VAR_OR_PROP{Stargate Id})
TRIGGER{Out}

if VAR.R{Player}:
	VAR.R{Player}.removeStargateAddress(VAR_OR_PROP{Stargate Id})
TRIGGER{Out}

if VAR.R{Player}:
	VAR.R{Player}.client.onPlayerCommunication(VAR_OR_PROP{Speaker}, VAR_OR_PROP{Speaker Flags}, VAR_OR_PROP{Channel}, VAR_OR_PROP{Text})
TRIGGER{Out}

if VAR.R{Player}:
	VAR.R{Player}.client.onSystemCommunication(VAR_OR_PROP{Text Type}, VAR_OR_PROP{String Id}, VAR_OR_PROP{Speaker}, [])
TRIGGER{Out}

dialogSet = DefMgr.get('interaction_set_map', VAR_OR_PROP{Dialog Set Map})
if VAR.R{Player} is not None and dialogSet is not None and VAR.R{Player}.addDialog(VAR_OR_PROP{Entity Template}, dialogSet, VAR_OR_PROP{Mission Id} or None):
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

dialogSet = DefMgr.get('interaction_set_map', VAR_OR_PROP{Dialog Set Map})
if VAR.R{Player} is not None and dialogSet is not None and VAR.R{Player}.removeDialog(VAR_OR_PROP{Entity Template}, dialogSet):
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

def dynamicCallback(entity):
	VAR.W{Updated Entity} = entity
	PROPAGATE{Updated Entity}
	TRIGGER.P{Update}
if VAR.R{Player} is not None and VAR.R{Entity} is not None:
	VAR.R{Player}.requestDynamicUpdate(VAR.R{Entity}, dynamicCallback)
TRIGGER{Out}

def dynUpdateCb(ent):
	#if CONNECTED(Static Mesh)
	if VAR.R{Static Mesh} is not None:
		ent.witnesses.onStaticMeshNameUpdate(VAR.R{Static Mesh}, ent.bodySet)
	#endif
		
	#if CONNECTED(Body Set)
	if VAR.R{Body Set} is not None:
		if ent.staticMeshName:
			ent.witnesses.onStaticMeshNameUpdate(ent.staticMeshName, VAR.R{Body Set})
		else:
			ent.witnesses.BeingAppearance(VAR.R{Body Set}, ent.components)
	#endif
		
	#if CONNECTED(Name)
	if VAR.R{Name} is not None:
		ent.witnesses.onBeingNameUpdate(VAR.R{Name})
	#endif
		
	#if CONNECTED(Alignment)
	if VAR.R{Alignment} is not None:
		ent.witnesses.onAlignmentUpdate(VAR.R{Alignment})
	#endif
		
	#if CONNECTED(Faction)
	if VAR.R{Faction} is not None:
		ent.witnesses.onFactionUpdate(VAR.R{Faction})
	#endif
		
	#if CONNECTED(Static Mesh)
	if VAR.R{Archetype} is not None:
		ent.witnesses.onArchetypeUpdate(VAR.R{Archetype})
	#endif
		
	#if CONNECTED(Aggression)
	if VAR.R{Aggression} is not None:
		ent.witnesses.onEntityProperty(Atrea.enums.GENERICPROPERTY_MobAggression, VAR.R{Aggression})
		ent.witnesses.onAggressionOverrideUpdate(VAR.R{Aggression})
	#endif
		
	#if CONNECTED(Level)
	if VAR.R{Level} is not None:
		ent.witnesses.onLevelUpdate(VAR.R{Level})
	#endif
		
	#if CONNECTED(Name Id)
	if VAR.R{Name Id} is not None:
		ent.witnesses.onBeingNameIDUpdate(VAR.R{Name Id})
	#endif
		
	#if CONNECTED(Event Set)
	if VAR.R{Event Set} is not None:
		ent.witnesses.onKismetEventSetUpdate(VAR.R{Event Set})
	#endif
		
	#if CONNECTED(Interaction Type)
	if VAR.R{Interaction Type} is not None:
		ent.witnesses.InteractionType(VAR.R{Interaction Type})
	#endif
		
	#if CONNECTED(Visible)
	if VAR.R{Visible} is not None:
		if VAR.R{Visible}:
			ent.witnesses.onVisible(1)
		else:
			ent.hide()
	#endif
	pass

if VAR.R{Player} is not None and VAR.R{Entity} is not None:
	VAR.R{Player}.requestDynamicUpdate(VAR.R{Entity}, dynUpdateCb)
	TRIGGER{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

#if CONNECTED(Out)
if VAR_OR_PROP{Active}:
	TRIGGER.P{Out}
#endif

#if CONNECTED(Expired)
# TODO: CancelTimer, avoid multiple In() calls and multiple parallel timers?
def timerCb():
	TRIGGER.P{Expired}
Atrea.addTimer(Atrea.getGameTime() + VAR_OR_PROP{Timeout}, timerCb)
#endif

if VAR.R{Source} is not None and VAR_OR_PROP{Sequence Id} is not None:
	target = VAR.R{Target}
	targetId = target.entityId if target else None
	VAR.R{Source}.playSequence(VAR_OR_PROP{Sequence Id}, targetId, VAR_OR_PROP{Primary Target},
		VAR_OR_PROP{Impact Time}, viewType = PROPERTY{View Type}, instanceId = VAR_OR_PROP{Instance Id},
		playOnSelf = PROPERTY{Visible to Source}, playOnWitnesses = PROPERTY{Visible to Witnesses})
TRIGGER{Out}

eventSet = DefMgr.get('event_set', VAR_OR_PROP{Event Set Id})
seq = eventSet.getSequence(VAR_OR_PROP{Event Id}) if eventSet else None
if seq is not None:
	VAR.W{Sequence Id} = seq.seqId
	PROPAGATE{Sequence Id}
	TRIGGER.P{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

def mgHandler(self, result):
	if result == Constants.MINIGAME_RESULT_Victory:
		TRIGGER.P{Won}
	elif result == Constants.MINIGAME_RESULT_Defeat:
		TRIGGER.P{Lost}
	else:
		TRIGGER.P{Failed}
	
gameIds = [k for k, v in Config.MINIGAME_NAMES.items() if v == VAR_OR_PROP{Minigame}]
assert(len(gameIds) == 1)
minigame = Minigame(PROPERTY{Display Name}, VAR_OR_PROP{Difficulty}, gameIds[0], 1, 0xffff, lambda mg, rc: mgHandler(self, rc))
if not VAR.R{Player}.requestStartMinigame(minigame):
	TRIGGER.P{Failed}

region = self.owner.space.transporters.get(VAR_OR_PROP{Region Id})
if region is not None:
	region.interact(self.owner)
	TRIGGER{Successful}
#if CONNECTED(Failed)
else:
	TRIGGER.P{Failed}
#endif

VAR.W{Output} = VAR.R{A} + VAR.R{B}
PROPAGATE{Output}
TRIGGER{Out}

VAR.W{Output} = VAR.R{A} - VAR.R{B}
PROPAGATE{Output}
TRIGGER{Out}

VAR.W{Output} = VAR.R{A} * VAR.R{B}
PROPAGATE{Output}
TRIGGER{Out}

VAR.W{Output} = VAR.R{A} / VAR.R{B}
PROPAGATE{Output}
TRIGGER{Out}
